import type { ScaleLinear, ScaleSymLog } from 'd3-scale';

import { DivAxisWrapper } from './DivAxisWrapper.js';
import { AxisBottom } from '../AxisBottom.js';
import { axisFontProps } from '../constants.js';
import { getTickLabelPropsForValueAxis } from '../utils/get-tick-label-props.js';

/**
 * @internal
 */
export interface ValueBottomAxisProps {
  scale: ScaleLinear<number, number> | ScaleSymLog<number, number>;
  containerWidth: number;
  containerHeight: number;
  label?: string;
  stroke?: string;
  ticks: string[];
  formattedTicks: string[];
}

const TICK_LABEL_PROPS = getTickLabelPropsForValueAxis('bottom');

/**
 * @internal
 */
export const ValueBottomAxis = (props: ValueBottomAxisProps) => {
  const {
    scale,
    containerHeight,
    containerWidth,
    label,
    stroke,
    ticks,
    formattedTicks,
  } = props;

  const tickFormat = (_: unknown, index: number) => formattedTicks[index];

  return (
    <DivAxisWrapper
      divAxisStyle={axisFontProps}
      ticks={formattedTicks}
      label={label}
      isTickVertical
    >
      <AxisBottom
        role="graphics-symbol"
        aria-label="value axis bottom"
        scale={scale}
        containerSize={containerWidth}
        height={containerHeight}
        tickValues={ticks}
        tickLabelProps={TICK_LABEL_PROPS}
        tickFormat={tickFormat}
        label={label}
        stroke={stroke}
      />
    </DivAxisWrapper>
  );
};

ValueBottomAxis['displayName'] = 'ValueBottomAxis';
